function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function money(n){ return (n==null)?'-':('$' + Number(n).toLocaleString('en-US')); }

const posById = {};
objects2d.forEach(function(o){ posById[o.id] = o; });
let gi = 0;
const buildings = massing.map(function(m){
  const p = posById[m.id];
  let x, z, w, dep;
  if (p) { x = p.x_pct; z = p.y_pct; w = p.width_pct || 5; dep = p.height_pct || 5; }
  else { const col = gi % 8, row = Math.floor(gi / 8); x = 8 + col*11; z = 10 + row*11; w = 6; dep = 6; gi++; }
  return { id: m.id, type: m.building_type || 'building', floors: m.floors || 1, height_m: m.height_m || 10, x, z, w, dep, label: (posById[m.id] && posById[m.id].label) || m.id };
});

const districtsRows = (plan.districts||[]).map(d => `<tr><td>${esc(d.id)}</td><td>${esc(d.name)}</td><td>${esc(d.purpose)}</td><td>${esc(d.area_pct)}%</td></tr>`).join('');
