<script>
var BUILDINGS=${buildingsJson};
var OBJ2D=${objects2dJson};
var massMap={};
BUILDINGS.forEach(function(m){massMap[m.id]=m;});
var RECS=OBJ2D.length>0?OBJ2D:BUILDINGS.map(function(m){return{id:m.id,type:m.type,x_pct:m.x,y_pct:m.z,width_pct:m.w,height_pct:m.dep,label:m.label||m.id};});

var PAL={residential_tower:'#60a5fa',residential_block:'#93c5fd',residential:'#bfdbfe',mixed_use:'#a78bfa',commercial:'#fbbf24',commercial_tower:'#f59e0b',commercial_block:'#fde68a',office_tower:'#f87171',office:'#fca5a5',retail:'#fb923c',civic_center:'#34d399',civic:'#6ee7b7',transit_hub:'#2dd4bf',transit:'#99f6e4',school:'#4ade80',hospital:'#ec4899',park:'#86efac',green_space:'#bbf7d0',road:'#cbd5e1',road_arterial:'#94a3b8',road_local:'#e2e8f0',warehouse:'#9ca3af',light_industry:'#6b7280',water:'#7dd3fc',open_space:'#d9f99d',building:'#94a3b8'};
function clr(t){
  if(!t)return'#94a3b8';
  var k=t.toLowerCase().replace(/[^a-z_]/g,'_');
  if(PAL[k])return PAL[k];
  var ks=Object.keys(PAL);
  for(var i=0;i<ks.length;i++){if(k.indexOf(ks[i])!==-1||ks[i].indexOf(k)!==-1)return PAL[ks[i]];}
  var h=0;for(var j=0;j<k.length;j++)h=(h*31+k.charCodeAt(j))&0xffffff;
  return'#'+('000000'+h.toString(16)).slice(-6);
}

function sw(v,btn){
  document.querySelectorAll('.tab').forEach(function(b){b.classList.remove('active');});
  document.querySelectorAll('.panel').forEach(function(p){p.classList.remove('active');});
  btn.classList.add('active');
  document.getElementById('p'+v).classList.add('active');
  if(v==='2d')draw2D();
  if(v==='3d'&&!window._3di)init3D();
}

function draw2D(){
  var cv=document.getElementById('c2d');
  var W=cv.parentElement.clientWidth||800;
  var H=Math.round(W*0.62);
  cv.width=W; cv.height=H; cv.style.height=H+'px';
  var ctx=cv.getContext('2d');
  ctx.fillStyle='#e8f5e9'; ctx.fillRect(0,0,W,H);
  ctx.strokeStyle='rgba(34,85,34,0.12)'; ctx.lineWidth=1;
  for(var gx=0;gx<=10;gx++){ctx.beginPath();ctx.moveTo(gx*(W/10),0);ctx.lineTo(gx*(W/10),H);ctx.stroke();}
  for(var gy=0;gy<=10;gy++){ctx.beginPath();ctx.moveTo(0,gy*(H/10));ctx.lineTo(W,gy*(H/10));ctx.stroke();}
  ctx.strokeStyle='#1e3a5f'; ctx.lineWidth=3; ctx.strokeRect(2,2,W-4,H-4);
  RECS.forEach(function(o){
    var xp=(o.x_pct||0)/100,yp=(o.y_pct||0)/100;
    var wp=Math.max(0.025,(o.width_pct||5)/100),hp=Math.max(0.018,(o.height_pct||5)/100);
    var px=Math.round(xp*W),py=Math.round(yp*H),pw=Math.round(wp*W),ph=Math.round(hp*H);
    var fill=clr(o.type);
    ctx.shadowColor='rgba(0,0,0,0.18)'; ctx.shadowBlur=5; ctx.shadowOffsetX=2; ctx.shadowOffsetY=2;
    ctx.fillStyle=fill; ctx.fillRect(px+2,py+2,pw-4,ph-4);
    ctx.shadowColor='transparent'; ctx.shadowBlur=0;
    ctx.strokeStyle='rgba(0,0,0,0.28)'; ctx.lineWidth=1; ctx.strokeRect(px+2,py+2,pw-4,ph-4);
    if(pw>36&&ph>14){
      ctx.fillStyle='rgba(0,0,0,0.72)';
      ctx.font='bold '+Math.min(12,Math.round(ph*0.3))+'px Segoe UI,Arial,sans-serif';
      ctx.textAlign='center'; ctx.textBaseline='middle';
      var lbl=o.label||o.type||o.id; if(lbl.length>16)lbl=lbl.slice(0,14)+'\u2026';
      ctx.fillText(lbl,px+pw/2,py+ph/2);
    }
  });
  drawCompass(ctx,W-46,46,30);
  ctx.fillStyle='rgba(15,23,42,0.55)'; ctx.fillRect(14,H-22,80,5);
  ctx.fillStyle='#fff'; ctx.fillRect(14,H-22,40,5);
  ctx.fillStyle='#1f2937'; ctx.font='10px Segoe UI,Arial'; ctx.textAlign='left'; ctx.fillText('Site boundary (0\u2013100%)',14,H-28);
  buildLg();
}

function drawCompass(ctx,cx,cy,r){
  ctx.save();
  ctx.beginPath(); ctx.arc(cx,cy,r,0,Math.PI*2);
  ctx.fillStyle='rgba(255,255,255,0.88)'; ctx.fill();
  ctx.strokeStyle='#94a3b8'; ctx.lineWidth=1; ctx.stroke();
  ctx.beginPath(); ctx.moveTo(cx,cy-r+5); ctx.lineTo(cx-5,cy+5); ctx.lineTo(cx,cy-2); ctx.closePath();
  ctx.fillStyle='#1e3a5f'; ctx.fill();
  ctx.beginPath(); ctx.moveTo(cx,cy-r+5); ctx.lineTo(cx+5,cy+5); ctx.lineTo(cx,cy-2); ctx.closePath();
  ctx.fillStyle='#94a3b8'; ctx.fill();
  ctx.fillStyle='#1e3a5f'; ctx.font='bold 10px Arial'; ctx.textAlign='center'; ctx.textBaseline='middle';
  ctx.fillText('N',cx,cy-r+1);
  ctx.restore();
}

function buildLg(){
  var seen={}; RECS.forEach(function(o){if(o.type)seen[o.type]=clr(o.type);});
  document.getElementById('lg2d').innerHTML=Object.keys(seen).map(function(t){
    return '<div class="li"><div class="sw" style="background:'+seen[t]+';border:1px solid rgba(0,0,0,0.2)"></div>'+t+'</div>';
  }).join('');
}

document.addEventListener('mousemove',function(e){
  var cv=document.getElementById('c2d');
  if(!cv||!cv.offsetParent)return;
  var rect=cv.getBoundingClientRect();
  var W=cv.width,H=cv.height;
  var cx=(e.clientX-rect.left)*(W/rect.width),cy=(e.clientY-rect.top)*(H/rect.height);
  var tt=document.getElementById('tip'),hit=null;
  RECS.forEach(function(o){
    var xp=(o.x_pct||0)/100*W,yp=(o.y_pct||0)/100*H;
    var wp=Math.max(0.025,(o.width_pct||5)/100)*W,hp=Math.max(0.018,(o.height_pct||5)/100)*H;
    if(cx>=xp&&cx<=xp+wp&&cy>=yp&&cy<=yp+hp)hit=o;
  });
  if(hit){
    var mm=massMap[hit.id];
    var lines=['<b>'+hit.label+'</b>','Type: '+hit.type,'Position: ('+Math.round(hit.x_pct||0)+'%, '+Math.round(hit.y_pct||0)+'%)','Size: '+Math.round(hit.width_pct||0)+'% \u00d7 '+Math.round(hit.height_pct||0)+'%'];
    if(mm){lines.push('Floors: '+mm.floors);lines.push('Height: '+mm.height_m+' m');}
    tt.innerHTML=lines.join('<br>'); tt.style.display='block';
    tt.style.left=(e.clientX+16)+'px'; tt.style.top=(e.clientY-10)+'px';
  } else { tt.style.display='none'; }
});

function init3D(){
  window._3di=true;
  var cv=document.getElementById('c3d'),T=window.THREE;
  if(!T||!cv)return;
  var scene=new T.Scene(); scene.background=new T.Color(0xdbeafe);
  var cam=new T.PerspectiveCamera(55,cv.clientWidth/cv.clientHeight,0.1,2000); cam.position.set(120,110,140);
  var rend=new T.WebGLRenderer({canvas:cv,antialias:true}); rend.setSize(cv.clientWidth,cv.clientHeight,false); rend.setPixelRatio(window.devicePixelRatio);
  var ctrl=new T.OrbitControls(cam,rend.domElement); ctrl.enableDamping=true; ctrl.target.set(50,0,50);
  scene.add(new T.AmbientLight(0xffffff,0.75));
  var dl=new T.DirectionalLight(0xffffff,0.7); dl.position.set(80,160,60); scene.add(dl);
  var gr=new T.Mesh(new T.PlaneGeometry(140,140),new T.MeshLambertMaterial({color:0xe5e7eb})); gr.rotation.x=-Math.PI/2; gr.position.set(50,0,50); scene.add(gr);
  scene.add(new T.GridHelper(140,14,0x9ca3af,0xcbd5e1));
  var CMAP={residential_tower:0x60a5fa,residential_block:0x93c5fd,residential:0xbfdbfe,mixed_use:0xa78bfa,commercial:0xfbbf24,commercial_tower:0xf59e0b,office_tower:0xef4444,retail:0xfb923c,civic_center:0x34d399,transit_hub:0x2dd4bf,school:0x22c55e,hospital:0xec4899,park:0x86efac,green_space:0xbbf7d0,warehouse:0x9ca3af,light_industry:0x6b7280};
  function hx(t){var k=(t||'').toLowerCase().replace(/[^a-z_]/g,'_');if(CMAP[k]!==undefined)return CMAP[k];var ks=Object.keys(CMAP);for(var i=0;i<ks.length;i++){if(k.indexOf(ks[i])!==-1||ks[i].indexOf(k)!==-1)return CMAP[ks[i]];}return 0x94a3b8;}
  BUILDINGS.forEach(function(b){
